import React, { useState } from "react";
// import { useDispatch } from "react-redux";
import styles from "./product-info.module.css";
import Title from "../../title";
import Quantity from "../quantity";
import Subscription from "../subscription";
import ButtonAdd from "../../button-add";
import Details from "../details";
import { useTranslation } from "react-i18next";

interface InfoProps {
  product: {
    id: number;
    img: string;
    name: string;
    price: number;
  };
}

const ProductInfo: React.FC<InfoProps> = ({ product }) => {
  const [t] = useTranslation("global");
  // Get the quantity from the Redux store using useSelector
  // const dispatch = useDispatch();
  // Local state for the quantity on the product details page
  const [quantity, setQuantity] = useState(1);

  console.log("ProductInfo - Current quantity:", quantity);

  return (
    <div className={styles.wrapper_product_info}>
      <Title level="h3" className={styles.title}>
        {product.name} Candleaf®
      </Title>
      <div className={styles.container_inner}>
        <div className={styles.container_left}>
          <span className={styles.price}>${product.price}</span>
          <div className={styles.wrapper_quantity}>
            <h6 className={styles.quantity_title}>{t}</h6>
            {/* Pass local quantity and handler to Quantity component */}
            <Quantity
              itemId={product.id}
              quantity={quantity}
              onQuantityChange={setQuantity}
              inCart={false}
            />
          </div>
        </div>
        <div className={styles.container_right}>
          <Subscription />
          {/* Use the ButtonAdd component with the "product" prop */}
          <ButtonAdd product={product} quantity={quantity} />
        </div>
      </div>
      <Details />
    </div>
  );
};

export default ProductInfo;
